import { Button } from '@tale-ui/react/button';

    export function Example() {
      return (
        <>
          <Button variant="primary" size="md">Click me</Button>
          <Button variant="neutral">Neutral</Button>
          <Button variant="ghost">Ghost</Button>
          <Button variant="danger">Danger</Button>
          <Button variant="danger-neutral">Outlined danger</Button>
          <Button variant="danger-ghost">Ghost danger</Button>
          <Button variant="inverse">Inverse</Button>
          <Button variant="primary" isPending>Saving…</Button>
          <Button variant="primary" isPending showTextWhileLoading>Saving…</Button>
        </>
      );
    }

pitfalls.detail:
The valid variants are `'primary'`, `'neutral'`, `'ghost'`, `'danger'`, `'danger-neutral'`, `'danger-ghost'`, and `'inverse'`. There is no `'link'` variant (use the `Link` component instead) and no `'secondary'` variant; when a prompt asks for a Cancel button or any secondary-action button, use `'neutral'` — never `'secondary'`.
    ```tsx
    import { Button } from '@tale-ui/react/button';

    export function Example() {
      return (
        <>
          <Button variant="primary" size="md">Click me</Button>
          <Button variant="neutral">Neutral</Button>
          <Button variant="ghost">Ghost</Button>
          <Button variant="danger">Danger</Button>
          <Button variant="danger-neutral">Outlined danger</Button>
          <Button variant="danger-ghost">Ghost danger</Button>
          <Button variant="inverse">Inverse</Button>
          <Button variant="primary" isPending>Saving…</Button>
          <Button variant="primary" isPending showTextWhileLoading>Saving…</Button>
        </>
      );
    }
    ```

