import { Calendar } from '@tale-ui/react/calendar';

    export function Example() {
      return (
        <Calendar.Root>
          <Calendar.Header>
            <Calendar.PreviousButton />
            <Calendar.Heading />
            <Calendar.NextButton />
          </Calendar.Header>
          <Calendar.Grid>
            <Calendar.GridHeader>
              {(day) => <Calendar.GridHeaderCell>{day}</Calendar.GridHeaderCell>}
            </Calendar.GridHeader>
            <Calendar.GridBody>
              {(date) => <Calendar.Cell date={date} />}
            </Calendar.GridBody>
          </Calendar.Grid>
        </Calendar.Root>
      );
    }

pitfalls.detail:
`Calendar.PreviousButton`, `Calendar.Heading`, and `Calendar.NextButton` must be placed inside `Calendar.Header`; placing them directly in `Calendar.Root` loses the flex layout.
    ```tsx
    import { Calendar } from '@tale-ui/react/calendar';

    export function Example() {
      return (
        <Calendar.Root>
          <Calendar.Header>
            <Calendar.PreviousButton />
            <Calendar.Heading />
            <Calendar.NextButton />
          </Calendar.Header>
          <Calendar.Grid>
            <Calendar.GridHeader>
              {(day) => <Calendar.GridHeaderCell>{day}</Calendar.GridHeaderCell>}
            </Calendar.GridHeader>
            <Calendar.GridBody>
              {(date) => <Calendar.Cell date={date} />}
            </Calendar.GridBody>
          </Calendar.Grid>
        </Calendar.Root>
      );
    }
    ```

