const baseProps = { className: 'base', onClick: handleClick };
const extraProps = { className: 'extra', 'aria-label': 'Button' };

const merged = mergeProps(baseProps, extraProps);
// → { className: 'extra base', onClick: handleClick, 'aria-label': 'Button' }

const a = { onClick: () => console.log('a') };
const b = { onClick: () => console.log('b') };

const merged = mergeProps(a, b);
// Clicking calls: b handler first, then a handler

const a = { onClick: () => console.log('a') };
const b = { onClick: (e) => { e.preventTaleUIHandler(); console.log('b only'); } };

const merged = mergeProps(a, b);
// Clicking calls: b handler only — a handler is skipped

import { MultiSelect } from '@tale-ui/react/multi-select';
import type { Selection } from 'react-aria-components';

const options = [
  { id: 'react', name: 'React' },
  { id: 'vue', name: 'Vue' },
  { id: 'angular', name: 'Angular' },
  { id: 'svelte', name: 'Svelte' },
];

function Example() {
  const [selected, setSelected] = React.useState<Selection>(new Set());

  return (
    <MultiSelect.Root
      label="Frameworks"
      placeholder="Select frameworks"
      items={options}
      selectedKeys={selected}
      onSelectionChange={setSelected}
    >
      {(item) => (
        <MultiSelect.Item id={item.id} textValue={item.name}>
          {item.name}
        </MultiSelect.Item>
      )}
    </MultiSelect.Root>
  );
}

import { useState } from 'react';
import { NavigationMenu } from '@tale-ui/react/navigation-menu';

function NavWithDropdown() {
  const [open, setOpen] = useState(false);

  return (
    <NavigationMenu.Root>
      <NavigationMenu.List>
        <NavigationMenu.Item>
          <NavigationMenu.Link href="#">Home</NavigationMenu.Link>
        </NavigationMenu.Item>
        <NavigationMenu.Item>
          <NavigationMenu.Trigger onClick={() => setOpen(!open)}>
            Products <NavigationMenu.Icon />
          </NavigationMenu.Trigger>
          {open && (
            <NavigationMenu.Popup>
              <NavigationMenu.Content>
                <NavigationMenu.Link href="#">Widget Pro</NavigationMenu.Link>
                <NavigationMenu.Link href="#">Gadget Plus</NavigationMenu.Link>
                <NavigationMenu.Link href="#">Tool Suite</NavigationMenu.Link>
              </NavigationMenu.Content>
            </NavigationMenu.Popup>
          )}
        </NavigationMenu.Item>
        <NavigationMenu.Item>
          <NavigationMenu.Link href="#">Contact</NavigationMenu.Link>
        </NavigationMenu.Item>
      </NavigationMenu.List>
    </NavigationMenu.Root>
  );
}

