    import { RadioGroup } from '@tale-ui/react/radio-group';
    import { Radio } from '@tale-ui/react/radio';

    export function Example() {
      return (
        <RadioGroup label="Favorite color">
          <Radio.Root value="red">
            <Radio.Indicator />
            Red
          </Radio.Root>
          <Radio.Root value="blue">
            <Radio.Indicator />
            Blue
          </Radio.Root>
        </RadioGroup>
      );
    }
    ```

