pitfalls.detail:
content inside `Trigger` renders as part of the interactive element, not the tooltip.
    ```tsx
    import { Tooltip } from '@tale-ui/react/tooltip';

    export function Example() {
      return (
        <Tooltip.Root>
          <Tooltip.Trigger className="tale-button tale-button--neutral tale-button--md">Hover me</Tooltip.Trigger>
          <Tooltip.Popup placement="top" offset={8}>
            <Tooltip.Arrow />
            Tooltip text
          </Tooltip.Popup>
        </Tooltip.Root>
      );
    }
    ```

